function showInitScript(){
  document.getElementById('init-script-wrap').style.display='block';
  document.getElementById('init-script-box').textContent=INIT_SCRIPT;
}

function copyInitScript(){
  var b=document.getElementById('copy-init-btn');
  function done(){b.textContent='\u2713 Kopiert!';setTimeout(function(){b.textContent='Kopier';},2000);}
  if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText(INIT_SCRIPT).then(done).catch(function(){fallbackCopy(INIT_SCRIPT,done);});}
  else fallbackCopy(INIT_SCRIPT,done);
}

function clearEmployees(){
  empList=[];
  localStorage.removeItem('bytt_mannskap_employees');
  document.getElementById('ac-loaded').style.display='none';
  document.getElementById('ac-status').style.display='none';
  document.getElementById('clear-emp-btn').style.display='none';
}

function loadEmployeesFromStorage(){
  try{
    var raw=localStorage.getItem('bytt_mannskap_employees');
    if(raw){
      var list=JSON.parse(raw);
      if(list&&list.length>0){
        empList=list;
        document.getElementById('ac-status').style.display='none';
        document.getElementById('ac-loaded').style.display='block';
        document.getElementById('ac-count').textContent=list.length;
        document.getElementById('clear-emp-btn').style.display='block';
        document.getElementById('init-script-wrap').style.display='none';
        return true;
      }
    }
  }catch(e){}
  return false;
}

// Try loading from localStorage on start
if(!loadEmployeesFromStorage()){
  // Also try direct ComboBox if MoveIT is open in same page (unlikely but possible)
  try{
    var cb=$('#EmployeeID').data('kendoComboBox');
    if(cb&&cb.dataSource&&cb.dataSource.data().length>0){
      empList=cb.dataSource.data().map(function(d){return {text:d.Text,guid:d.Value};});
      document.getElementById('ac-loaded').style.display='block';
      document.getElementById('ac-count').textContent=empList.length;
      document.getElementById('clear-emp-btn').style.display='block';
    }
  }catch(e){}
}

// Poll localStorage every second for 60s in case user pastes init script
var _acTimer=setInterval(function(){
  if(loadEmployeesFromStorage())clearInterval(_acTimer);
},1000);
setTimeout(function(){clearInterval(_acTimer);},60000);

// ─── Theme / mode / status ──────────────────────────────────────
var selectedStatus='pending';
var selectedMode='intern';

function setMode(m){
  selectedMode=m;
  document.getElementById('mode-intern').className='mode-btn'+(m==='intern'?' active':'');
  document.getElementById('mode-ekstern').className='mode-btn'+(m==='ekstern'?' active':'');
  document.getElementById('wrap-intern').style.display=m==='intern'?'':'none';
  document.getElementById('wrap-ekstern').style.display=m==='ekstern'?'':'none';
}

function selectStatus(s){
  selectedStatus=s;
  document.getElementById('btn-pending').className='status-btn'+(s==='pending'?' active-pending':'');
  document.getElementById('btn-confirm').className='status-btn'+(s==='confirm'?' active-confirm':'');
}

function toggleDD(id){
  var el=document.getElementById(id);
  var was=el.classList.contains('open');
  document.querySelectorAll('.dd-menu').forEach(function(m){m.classList.remove('open');});
  if(!was)el.classList.add('open');
}
document.addEventListener('click',function(e){if(!e.target.closest('.dd-wrap'))document.querySelectorAll('.dd-menu').forEach(function(m){m.classList.remove('open');});});

function setTheme(t){
  document.documentElement.setAttribute('data-theme',t);
  var lb={'metro-black':'Dark Mode','default':'Default','matrix':'The Matrix','liquid-glass':'Liquid Glass'};
  document.getElementById('theme-label').textContent=lb[t]||t;
  document.querySelectorAll('#theme-dd .dd-item').forEach(function(o){o.classList.toggle('active',o.textContent===(lb[t]||t));});
  document.getElementById('theme-dd').classList.remove('open');
  localStorage.setItem('bytt-theme',t);
  if(t==='matrix')startMatrix();else stopMatrix();
}

var mc=null,mx=null,mi=null,mc2='\u30A2\u30A4\u30A6\u30A8\u30AA0123456789ABCDEF',md=[];
function initM(){mc=document.getElementById('matrix-canvas');mx=mc.getContext('2d');mc.width=window.innerWidth;mc.height=window.innerHeight;md=Array(Math.floor(window.innerWidth/14)).fill(1);}
function drawM(){mx.fillStyle='rgba(0,0,0,0.05)';mx.fillRect(0,0,mc.width,mc.height);mx.fillStyle='#00ff41';mx.font='13px Courier New';md.forEach(function(y,i){var ch=mc2[Math.floor(Math.random()*mc2.length)];mx.fillText(ch,i*14,y*14);if(y*14>mc.height&&Math.random()>0.975)md[i]=0;md[i]++;});}
function startMatrix(){initM();if(mi)clearInterval(mi);mi=setInterval(drawM,50);}
function stopMatrix(){if(mi)clearInterval(mi);mi=null;if(mx)mx.clearRect(0,0,mc?mc.width:0,mc?mc.height:0);}

function validate(){
  var fra=document.getElementById('f-fra').value.trim();
  if(!fra)return false;
  if(selectedMode==='intern')return !!document.getElementById('f-til-intern').value.trim();
  return !!document.getElementById('f-til-ekstern').value;
}

function nullstill(){
  ['f-fra','f-til-intern','f-project','f-name','f-date-from','f-date-to'].forEach(function(id){document.getElementById(id).value='';});
  document.getElementById('f-til-ekstern').value='';
  document.getElementById('code-output').textContent='';
  document.getElementById('code-wrap').style.display='none';
  document.getElementById('copy-btn').style.display='none';
  document.getElementById('stop-banner').classList.remove('show');
  document.getElementById('validation-error').classList.remove('show');
}

function generateScript(){
  var err=document.getElementById('validation-error');
  if(!validate()){err.classList.add('show');return;}
  err.classList.remove('show');
  var fra=document.getElementById('f-fra').value.trim();
  var tilIntern=document.getElementById('f-til-intern').value.trim();
  var rolleVal=document.getElementById('f-til-ekstern').value;
  var rolleMap={'1005':'Servicemedarbeider','1004':'Monт\xF8r','1003':'Arbeidsleder'};
  var rolleNavn=rolleMap[rolleVal]||'';
  var rolleTekst=rolleVal?(rolleVal+' ('+rolleNavn+')'):'';
  var p=document.getElementById('f-project').value.trim();
  var n=document.getElementById('f-name').value.trim();
  var df=document.getElementById('f-date-from').value.trim();
  var dt=document.getElementById('f-date-to').value.trim();
  var statuses=[];
  if(document.getElementById('chk-draft').checked)statuses.push('Draft');
  if(document.getElementById('chk-pending').checked)statuses.push('Pending');
  if(document.getElementById('chk-confirm').checked)statuses.push('Confirm');
  document.getElementById('code-output').textContent=buildScript(fra,tilIntern,rolleVal,rolleNavn,rolleTekst,p,n,df,dt,selectedMode,selectedStatus,statuses);
  document.getElementById('code-wrap').style.display='block';
  document.getElementById('copy-btn').style.display='block';
  document.getElementById('stop-banner').classList.add('show');
}

function fallbackCopy(txt,cb){
  var ta=document.createElement('textarea');ta.value=txt;ta.style.position='fixed';ta.style.top='-9999px';
  document.body.appendChild(ta);ta.focus();ta.select();
  try{document.execCommand('copy');cb();}catch(e){}
  document.body.removeChild(ta);
}
function copyScript(){
  var txt=document.getElementById('code-output').textContent;
  var b=document.getElementById('copy-btn');
  function done(){b.textContent='\u2713 Kopiert!';setTimeout(function(){b.textContent='Kopier';},2000);}
  if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText(txt).then(done).catch(function(){fallbackCopy(txt,done);});}
  else fallbackCopy(txt,done);
}
function copyStop(){
  var b=document.querySelector('.stop-btn');
  var banner=document.getElementById('stop-banner');
  function done(){b.textContent='\u2713 Kopiert!';banner.classList.add('alarm');setTimeout(function(){banner.classList.remove('alarm');b.textContent='Kopier n\xF8dstopp';},900);}
  if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText('window.__stopByttMannskap=true').then(done).catch(function(){fallbackCopy('window.__stopByttMannskap=true',done);});}
  else fallbackCopy('window.__stopByttMannskap=true',done);
}

